      newAnsweredQuestions[state.currentQuestionIndex] = true;
      newUserAnswers[state.currentQuestionIndex] = state.userDefinition;
      newAiResults[state.currentQuestionIndex] = action.payload.isCorrect;

      return {
        ...state,
