        },
      };

    case "SET_QUESTION_START_TIME":
      return {
        ...state,
        questionStartTime: action.payload,
      };

    case "LOAD_QUESTION_STATE":
      return {
        ...state,
        userDefinition: action.payload.userDefinition,
        showResult: action.payload.showResult,
      };

    default:
      return state;
  }
}

