import { createOpenRouter } from "@openrouter/ai-sdk-provider";
import { generateObject } from "ai";
import { NextRequest, NextResponse } from "next/server";
import { z } from "zod";

const supportedTasks = [
  "validate-user-definition",
  "validate-user-sentence",
] as const;

const feedbackSchema = z.object({
  correct: z.boolean(),
  exampleSentence: z.string(),
  aiResponse: z.string(),
  hint: z.string(),
});

type SupportedTask = (typeof supportedTasks)[number];

function isSupportedTask(task: unknown): task is SupportedTask {
  return typeof task === "string" && supportedTasks.includes(task as SupportedTask);
}

function stringFrom(value: unknown) {
  return typeof value === "string" ? value.trim() : "";
}

function missingFieldsResponse(fields: string[]) {
  return NextResponse.json(
    {
      success: false,
      message: `Missing required field${fields.length === 1 ? "" : "s"}: ${fields.join(
        ", "
      )}`,
    },
    { status: 400 }
  );
}

export async function POST(request: NextRequest) {
  let body: unknown;

  try {
    body = await request.json();
  } catch {
    return NextResponse.json(
      { success: false, message: "Request body must be valid JSON." },
      { status: 400 }
    );
  }

  const requestBody = body as {
    task?: unknown;
    message?: unknown;
    data?: Record<string, unknown>;
  };

  if (!isSupportedTask(requestBody.task)) {
    return NextResponse.json(
      {
        success: false,
        message: `Unsupported or missing task. Supported tasks: ${supportedTasks.join(
          ", "
        )}.`,
      },
      { status: 400 }
    );
  }

  const data = requestBody.data ?? {};
  const word = stringFrom(data.word);
  const definition = stringFrom(data.correctDefinition ?? data.definition);
  const exampleSentence = stringFrom(data.exampleSentence);
  const message = stringFrom(requestBody.message);

  if (requestBody.task === "validate-user-definition") {
    const userDefinition = stringFrom(data.userDefinition ?? requestBody.message);
    const missingFields = [
      !word && "data.word",
      !userDefinition && "data.userDefinition",
      !definition && "data.correctDefinition",
    ].filter(Boolean) as string[];

    if (missingFields.length > 0) {
      return missingFieldsResponse(missingFields);
    }

    return generateFeedback({
      task: requestBody.task,
      word,
      userInput: userDefinition || message,
      definition,
      exampleSentence,
    });
  }

  const userSentence = stringFrom(data.userSentence ?? requestBody.message);
  const missingFields = [
    !word && "data.word",
    !userSentence && "data.userSentence",
    !definition && "data.definition",
  ].filter(Boolean) as string[];

  if (missingFields.length > 0) {
    return missingFieldsResponse(missingFields);
  }

  return generateFeedback({
    task: requestBody.task,
    word,
    userInput: userSentence || message,
    definition,
    exampleSentence,
  });
}

async function generateFeedback({
  task,
  word,
  userInput,
  definition,
  exampleSentence,
}: {
  task: SupportedTask;
  word: string;
  userInput: string;
  definition: string;
  exampleSentence: string;
}) {
  const apiKey = process.env.OPENROUTER_KEY;

  if (!apiKey) {
    return NextResponse.json(
      {
        success: false,
        message: "AI feedback is unavailable because OPENROUTER_KEY is not configured.",
      },
      { status: 503 }
    );
  }

  const openrouter = createOpenRouter({
    apiKey,
  });

  const model = openrouter.chat(
    process.env.OPENROUTER_MODEL ?? "openai/gpt-4o-mini"
  );

  const prompt =
    task === "validate-user-definition"
      ? `Evaluate this learner definition for the vocabulary word.

Word: ${word}
Correct definition: ${definition}
Example sentence: ${exampleSentence || "No example provided."}
Learner definition: ${userInput}

Decide whether the learner definition captures the important meaning. Be generous about wording but strict about incorrect meanings.`
      : `Evaluate this learner sentence for the vocabulary word.

Word: ${word}
Definition: ${definition}
Reference example: ${exampleSentence || "No example provided."}
Learner sentence: ${userInput}

Decide whether the sentence uses the word naturally and with the intended meaning. The sentence must include the vocabulary word or a direct inflected form, be a complete learner-authored sentence, and make sense in context.`;

  try {
    const { object } = await generateObject({
      model,
      schema: feedbackSchema,
      mode: "json",
      temperature: 0.2,
      system:
        "You are a concise SAT vocabulary tutor. Return JSON only. Keep aiResponse to one or two helpful sentences, and make hint a short actionable tip.",
      prompt,
    });

    return NextResponse.json({
      success: true,
      result: object,
    });
  } catch (error) {
    console.error("OpenRouter vocabulary feedback error:", error);

    return NextResponse.json(
      {
        success: false,
        message: "AI feedback is unavailable. Please use local evaluation.",
      },
      { status: 502 }
    );
  }
}

